// ==========================================
const Config = {
    default:[
        { id: 1, name: "哭包剧情摘要", enabled: true, mode: "simple", startMarker: '<details data-info="archive">', endMarker: "</details>", themeId: 'native_default' },
        { id: 2, name: "哭包剧情走向", enabled: true, mode: "simple", startMarker: '<details data-fate="destiny">', endMarker: "</details>", themeId: 'native_default' },
        { id: 3, name: "哭包小剧场", enabled: true, mode: "simple", startMarker: '<details data-fate="side_theater">', endMarker: "</details>", themeId: 'native_default' },
        { id: 4, name: "哭包其他数据", enabled: true, mode: "simple", startMarker: '<details data-info="record">', endMarker: "</details>", themeId: 'native_default' }
    ], 
    get: () => {
        try {
            const raw = localStorage.getItem(SETTINGS_KEY);
            if (!raw) return Config.default;
            const parsed = JSON.parse(raw);
            if (!Array.isArray(parsed)) return Config.default;
            return parsed.map(p => ({ ...p, mode: p.mode || 'simple', themeId: p.themeId || 'native_default' }));
        } catch { return Config.default; }
    },
    save: (data) => {
        const cleanData = data.map(item => { const { _expanded, ...rest } = item; return rest; });
        localStorage.setItem(SETTINGS_KEY, JSON.stringify(cleanData));
    }
};

const DEFAULT_VARS = {
    appBg: '#f4f0e6', appBgOpacity: 100, appBgImgOpacity: 100, appBgImgBlur: 0,
    cardBg: '#ffffff', cardBgOpacity: 100, cardBgImgOpacity: 100, cardBgImgBlur: 0, 
    stroke: '#2a2a2a', accent: '#e57c65',
    accentBg: '#e57c65', accentBgOpacity: 15, 

    quoteBorder: '#e57c65', quoteBg: '#000000', quoteBgOpacity: 2, quoteText: '#555555',
    codeText: '#e57c65', codeBg: '#e57c65', codeBgOpacity: 15,
    tagBg: '#e57c65', tagBgOpacity: 15, tagText: '#e57c65', 
    rpgProgressBg: '#000000', rpgProgressBgOpacity: 8,

    metaColor: '#888888', metaTextOpen: '▲ OPEN', metaTextClose: '▼ CLOSE',
    textMain: '#2a2a2a', textSub: '#555555', radiusBox: 14, radiusBtn: 10, borderWidth: 1.5,
    rpgBadgeBg: '#e57c65', rpgBadgeText: '#ffffff', rpgProgressFill: '#e57c65',
    appBgImg: '', cardBgImg: '', fontFamily: 'inherit', fontUrl: ''
};

const ThemeConfig = {
    default: { activeId: 'native_default', themes:[{ id: 'native_default', name: '默认 (Native)', readonly: true, vars: { ...DEFAULT_VARS }, customCss: '' }] },
    get: () => {
        try {
            const raw = localStorage.getItem(THEMES_KEY);
            if (!raw) return ThemeConfig.default;
            const parsed = JSON.parse(raw);

            if (!parsed || !Array.isArray(parsed.themes) || parsed.themes.length === 0) return ThemeConfig.default;

            parsed.themes.forEach(t => { 
                if (!t.vars) t.vars = {};
                t.vars = { ...DEFAULT_VARS, ...t.vars }; 
                if(!t.vars.quoteBorder) t.vars.quoteBorder = t.vars.accent || '#e57c65';
                if(!t.vars.quoteBg) t.vars.quoteBg = '#000000';
                if(t.vars.quoteBgOpacity === undefined) t.vars.quoteBgOpacity = 2;
                if(!t.vars.quoteText) t.vars.quoteText = t.vars.textSub || '#555555';
                if(!t.vars.codeText) t.vars.codeText = t.vars.accent || '#e57c65';
                if(!t.vars.codeBg) t.vars.codeBg = t.vars.accentBg || '#e57c65';
                if(t.vars.codeBgOpacity === undefined) t.vars.codeBgOpacity = t.vars.accentBgOpacity || 15;
                if(!t.vars.rpgProgressBg) t.vars.rpgProgressBg = '#000000';
                if(t.vars.rpgProgressBgOpacity === undefined) t.vars.rpgProgressBgOpacity = 8;
            });
            return parsed;
        } catch { return ThemeConfig.default; }
    },
    save: (data) => { localStorage.setItem(THEMES_KEY, JSON.stringify(data)); },

    generateCssString: (vars, customCss, selector = ":root") => {
        const hexToRgba = (colorStr, opacity) => {
            if (!colorStr || typeof colorStr !== 'string') return 'transparent';
            if (colorStr.startsWith('#') && (colorStr.length === 7 || colorStr.length === 4)) {
                let hex = colorStr.replace('#', '');
                if (hex.length === 3) hex = hex.split('').map(x => x + x).join('');
                const r = parseInt(hex.substring(0, 2), 16);
                const g = parseInt(hex.substring(2, 4), 16);
                const b = parseInt(hex.substring(4, 6), 16);
                return `rgba(${r}, ${g}, ${b}, ${opacity / 100})`;
            }
            return colorStr; 
        };

        let fontImport = '';
        if (vars.fontUrl && vars.fontUrl.startsWith('http')) fontImport = `@import url("${vars.fontUrl}");`;

        let scopedCustomCss = '';
        if (customCss) {
            scopedCustomCss = customCss.replace(/THIS/g, selector);
        }

        const cssBody = `${selector} {
    --sb-app-bg: ${hexToRgba(vars.appBg, vars.appBgOpacity)};
    --sb-bg-img-opacity: ${vars.appBgImgOpacity / 100};
    --sb-bg-img-blur: ${vars.appBgImgBlur}px;
    --sb-card-bg: ${hexToRgba(vars.cardBg, vars.cardBgOpacity)};
    --sb-card-bg-img-opacity: ${vars.cardBgImgOpacity / 100};
    --sb-card-bg-img-blur: ${vars.cardBgImgBlur}px;
    --sb-stroke: ${vars.stroke};
    --sb-accent: ${vars.accent};

    --sb-quote-border: ${vars.quoteBorder};
    --sb-quote-bg: ${hexToRgba(vars.quoteBg, vars.quoteBgOpacity)};
    --sb-quote-text: ${vars.quoteText};
    --sb-code-text: ${vars.codeText};
    --sb-code-bg: ${hexToRgba(vars.codeBg, vars.codeBgOpacity)};

    --sb-tag-bg: ${hexToRgba(vars.tagBg, vars.tagBgOpacity)};
    --sb-tag-text: ${vars.tagText};

    --sb-meta-color: ${vars.metaColor};
    --sb-meta-text-open: "${vars.metaTextOpen}";
    --sb-meta-text-close: "${vars.metaTextClose}";
    --sb-text-main: ${vars.textMain};
    --sb-text-sub: ${vars.textSub};
    --sb-radius-box: ${vars.radiusBox}px;
    --sb-radius-btn: ${vars.radiusBtn}px;
    --sb-border-width: ${vars.borderWidth}px;

    --sb-rpg-badge-bg: ${vars.rpgBadgeBg};
    --sb-rpg-badge-text: ${vars.rpgBadgeText};
    --sb-rpg-progress-fill: ${vars.rpgProgressFill};
    --sb-rpg-track-bg: ${hexToRgba(vars.rpgProgressBg, vars.rpgProgressBgOpacity)};

    --sb-app-bg-img: ${vars.appBgImg ? `url("${vars.appBgImg}")` : 'none'};
    --sb-card-bg-img: ${vars.cardBgImg ? `url("${vars.cardBgImg}")` : 'none'};
    --sb-custom-font: ${vars.fontFamily ? vars.fontFamily : 'inherit'};
}
${scopedCustomCss || ''}`.trim();

        return { fontImport, cssBody };
    },
    apply: () => {
        let data = ThemeConfig.get();
        if (!data || !data.themes || data.themes.length === 0) data = ThemeConfig.default;
        if (!$(`#${THEME_STYLE_ID}`).length) $('head').append(`<style id="${THEME_STYLE_ID}"></style>`);

        let importsSet = new Set();
        let allCss = '';

        data.themes.forEach(t => {
            const vars = { ...DEFAULT_VARS, ...t.vars };
            const generated = ThemeConfig.generateCssString(vars, t.customCss, `.sb-theme-${t.id}`);
            if (generated.fontImport) importsSet.add(generated.fontImport);
            allCss += generated.cssBody + '\n\n';
        });

        const fallbackTheme = data.themes.find(t => t.id === data.activeId) || data.themes[0];
        if (fallbackTheme) {
            const fbVars = { ...DEFAULT_VARS, ...fallbackTheme.vars };
            const fbGenerated = ThemeConfig.generateCssString(fbVars, '', `:root`); 
            allCss += '\n/* 基础占位符 */\n' + fbGenerated.cssBody;
        }

        $(`#${THEME_STYLE_ID}`).html(Array.from(importsSet).join('\n') + '\n' + allCss);
    }
};

