const App = {
    buildSafeRegexStr: (marker) => {
        let escaped = marker.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
        escaped = escaped.replace(/\\"/g, '["\']?'); 
        escaped = escaped.replace(/[ \t]+/g, '\\s+'); 
        escaped = escaped.replace(/>/g, '\\s*>'); 
        escaped = escaped.replace(/</g, '<\\s*'); 
        return escaped;
    },

    buildSafeRawRegex: (marker, mode = 'simple') => {
        if (!marker) return '$';
        if (mode === 'regex') return marker; 
        let escaped = App.buildSafeRegexStr(marker);
        escaped = escaped.replace(/\r?\n/g, '\\s*'); 
        return escaped;
    },

    buildSafeHtmlRegex: (marker, mode = 'simple') => {
        if (!marker) return '$';
        if (mode === 'regex') return marker; 
        let escaped = App.buildSafeRegexStr(marker);
        escaped = escaped.replace(/\r?\n/g, '\\s*(?:<br[^>]*>|<\\/?p[^>]*>)?\\s*');
        return escaped;
    },

    insertText: (text) => {
        const $textarea = $('#send_textarea');
        if ($textarea.length) {
            $textarea.val(text).trigger('input').focus();
            const evt = new Event('input', { bubbles: true });
            $textarea[0].dispatchEvent(evt);
        }
    },

    syncToChatMemory: (mesId, codeBlockIndex, newContent) => {
        const chat = SillyTavern.getContext().chat;
        if (!chat || !chat[mesId]) return;

        let originalText = chat[mesId].mes;
        const delim = "```"; 
        const escapedDelim = delim.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
        const regex = new RegExp(`(${escapedDelim})([\\s\\S]*?)(${escapedDelim})`, 'g');

        let currentIdx = 0;
        let replaceSuccess = false;

        const newText = originalText.replace(regex, (matchStr, p1, p2, p3) => {
            if (currentIdx === codeBlockIndex) {
                replaceSuccess = true;
                return `${p1}\n${newContent}\n${p3}`;
            }
            currentIdx++;
            return matchStr;
        });

        if (replaceSuccess) {
            chat[mesId].mes = newText;
            if (SillyTavern.saveChat) SillyTavern.saveChat();
        }
    },

    generateBtnHtml: (content, idx) => {
        let displayContent = content.trim(); 
        return `
            <div class="sb-item-btn" data-idx="${idx}" data-content="${_.escape(content)}">
                <div class="sb-btn-inner"><span class="sb-btn-text">${_.escape(displayContent)}</span></div>
                <div class="sb-edit-icon" title="编辑选项">${SVGS.edit}</div>
            </div>
        `;
    },

    getValidBlockIndices: (fullText, startMarker, endMarker, mode = 'simple') => {
        const indices =[];
        const regex = /```([\s\S]*?)```/g;
        let match;
        let counter = 0;
        const validRanges =[];

        const escStart = App.buildSafeRawRegex(startMarker, mode);
        const escEnd = endMarker ? App.buildSafeRawRegex(endMarker, mode) : '$';
        const rangeRegex = new RegExp(`(${escStart})([\\s\\S]*?)(${escEnd})`, 'ig');

        let rangeMatch;
        while ((rangeMatch = rangeRegex.exec(fullText)) !== null) {
            if (rangeMatch.index === rangeRegex.lastIndex) { rangeRegex.lastIndex++; }
            validRanges.push({ start: rangeMatch.index, end: rangeMatch.index + rangeMatch[0].length });
        }

        while ((match = regex.exec(fullText)) !== null) {
            if (match.index === regex.lastIndex) { regex.lastIndex++; }
            const pos = match.index;
            const inRange = validRanges.some(r => pos > r.start && pos < r.end);
            if (inRange) { 
                let content = match[1].trim();
                content = content.replace(/^(?:text|plaintext|md|markdown)\s*\n/i, '');
                indices.push({ globalIndex: counter, content: content }); 
            }
            counter++;
        }
        return indices;
    },

    processMessage: (domElement) => {
        const $el = $(domElement);
        const $mesText = $el.find('.mes_text');
        if ($mesText.length === 0) return;

        if ($el.attr(PROCESSED_ATTR) === 'true') {
            if ($mesText.children('.sb-rendered-wrapper').length === 0 && $mesText.children('.sb-original-wrapper').length === 0) {
                $el.removeAttr(PROCESSED_ATTR); 
            } else { return; }
        }

        const mesId = $el.attr('mesid');
        const context = SillyTavern.getContext();
        if (!mesId || !context.chat || !context.chat[mesId]) return;

        const rawText = context.chat[mesId].mes;
        const configArray = Config.get();

        let cleanHtml = '';
        let isRebuild = false;

        if ($mesText.children('.sb-original-wrapper').length > 0) {
            cleanHtml = $mesText.children('.sb-original-wrapper').html();
            isRebuild = true;
        } else {
            cleanHtml = $mesText.html();
        }

        let htmlContent = cleanHtml;
        let isModified = false;

        configArray.forEach(conf => {
            if (!conf.enabled || !conf.startMarker || conf.startMarker.trim() === '') return;

            let safeEndMarker = conf.endMarker;
            if (safeEndMarker && conf.mode !== 'regex') {
                const endCheck = safeEndMarker.trim();
                if (endCheck.length === 0) safeEndMarker = ""; 
            }

            const rawEscStart = App.buildSafeRawRegex(conf.startMarker, conf.mode);
            if (!(new RegExp(rawEscStart, 'i')).test(rawText)) return;

            const validBlocks = App.getValidBlockIndices(rawText, conf.startMarker, safeEndMarker, conf.mode);

            const htmlEscStart = App.buildSafeHtmlRegex(conf.startMarker, conf.mode);
            const htmlEscEnd = safeEndMarker ? App.buildSafeHtmlRegex(safeEndMarker, conf.mode) : '$';
            const rangeRegex = new RegExp(`(${htmlEscStart})([\\s\\S]*?)(${htmlEscEnd})`, 'ig');

            if (rangeRegex.test(htmlContent)) {
                rangeRegex.lastIndex = 0; 
                let localBlockPtr = 0;

                htmlContent = htmlContent.replace(rangeRegex, (fullMatch, p1, p2, p3) => {
                    isModified = true;
                    let originalBlock = fullMatch;
                    let panelTitle = conf.name || "剧情走向";

                    const summaryRegex = /<summary[^>]*>([\s\S]*?)<\/summary>/i;
                    const summaryMatch = summaryRegex.exec(originalBlock);
                    if (summaryMatch) {
                        let extracted = summaryMatch[1].replace(/<[^>]+>/g, '').trim(); 
                        let cleanExtracted = extracted.replace(/^[▼▲▶►▣■✧]\s*/, '').replace(/\s*✧$/, '').trim(); 
                        if (cleanExtracted === '详情' || cleanExtracted === 'Details' || cleanExtracted === '') {
                            panelTitle = conf.name || "剧情走向";
                        } else { panelTitle = cleanExtracted; }
                        originalBlock = originalBlock.replace(summaryMatch[0], ''); 
                    } else if (conf.mode !== 'regex') {
                        let strippedStart = conf.startMarker.replace(/<[^>]+>/g, '').trim();
                        if (strippedStart && strippedStart !== '详情' && strippedStart !== 'Details') {
                            panelTitle = strippedStart;
                        } else if (conf.name) {
                            panelTitle = conf.name;
                        }
                    }

                    let bodyHtml = originalBlock.replace(p1, '');
                    if (p3 && p3 !== '$') bodyHtml = bodyHtml.replace(p3, '');

                    bodyHtml = bodyHtml.replace(/<\/?details[^>]*>/gi, '').replace(/<\/details>/gi, '')
                        .replace(/<\/?summary[^>]*>/gi, '').replace(/<\/summary>/gi, '')
                        .replace(/^(?:<br\s*\/?>|\s|&nbsp;|<p><\/p>)+/gi, '') 
                        .replace(/^[\s▣■]+/, ''); 

                    let localFinalBody = bodyHtml.replace(/<pre[^>]*>[\s\S]*?<\/pre>/gi, (preHtml) => {
                        if (localBlockPtr < validBlocks.length) {
                            const blockData = validBlocks[localBlockPtr];
                            localBlockPtr++;
                            return App.generateBtnHtml(blockData.content, blockData.globalIndex);
                        }
                        return preHtml;
                    });

                    localFinalBody = localFinalBody.replace(/🔸([^<\n]+)/g, '<div class="sb-rpg-title"><span style="opacity:0.7; margin-right:4px;">❖</span>$1</div>');
                    localFinalBody = localFinalBody.replace(/\[\s*(?:<[^>]+>|`)*\s*([^\]<]*?进度[^0-9<]*?)\s*(?:<\/[^>]+>|`)*\s*(?:<[^>]+>|`)*\s*(\d+(?:\.\d+)?)\s*(?:<\/[^>]+>|`)*\s*[%％]?\s*\/\s*(?:<[^>]+>|`)*\s*100\s*(?:<\/[^>]+>|`)*\s*[%％]?.*?\]/g, (match, label, percent) => {
                        return `<div class="sb-rpg-progress-box"><div class="sb-rpg-progress-label"><span>${label.trim()}</span> <span style="color:var(--sb-rpg-progress-fill);"><strong>${percent}%</strong></span></div><div class="sb-rpg-progress-track"><div class="sb-rpg-progress-fill" style="width: ${percent}%;"></div></div></div>`;
                    });
                    localFinalBody = localFinalBody.replace(/(当前|好感|数值|情意值|本次|上次|变化|增减)[\s:：]+(?:<[^>]+>|`)*\s*([\+\-]?\d+(?:\.\d+)?)(?:\/\d+)?\s*(?:<\/[^>]+>|`)*/gi, (match, label, val) => {
                        let num = Math.min(100, Math.max(0, parseFloat(val)));
                        if(isNaN(num)) num = 0;
                        return `<div class="sb-rpg-mini-bar"><span class="sb-mini-bar-label">${label}</span><div style="flex-grow:1; margin: 0 10px;"><div class="sb-rpg-progress-track" style="height:6px;"><div class="sb-rpg-progress-fill" style="width: ${num}%;"></div></div></div><span style="font-weight:bold; color:var(--sb-rpg-progress-fill); font-family:monospace;">${val}</span></div>`;
                    });

                    localFinalBody = localFinalBody.replace(/【([^】]+)】/g, '<span class="sb-bracket-tag">【$1】</span>');

                    const themeClass = `sb-theme-${conf.themeId || 'native_default'}`;

                    return `
                        </p></div>
                        <details class="sb-container sb-style-normal ${themeClass}">
                            <summary class="sb-header"><span class="sb-title">${panelTitle}</span><span class="sb-meta"></span></summary>
                            <div class="sb-content"><div class="sb-body-text">${localFinalBody}</div></div>
                        </details>
                        <div><p>
                    `;
                });
            }
        });

        if (isModified) {
            $el.attr(PROCESSED_ATTR, 'true');
            if (isRebuild) {
                $mesText.children('.sb-rendered-wrapper').html(htmlContent);
            } else {
                $mesText.empty();
                const $orig = $('<div class="sb-original-wrapper" style="display:none;" aria-hidden="true"></div>').html(cleanHtml);
                const $rendered = $('<div class="sb-rendered-wrapper"></div>').html(htmlContent);
                $mesText.append($orig).append($rendered);
            }
            App.bindEvents($el, mesId);
        } else if (isRebuild) {
            $mesText.html(cleanHtml);
            $el.removeAttr(PROCESSED_ATTR);
        }
    },

    bindEvents: ($messageEl, mesId) => {
        $messageEl.find('.sb-item-btn').each(function() {
            const $btn = $(this);
            const content = $btn.attr('data-content'); 
            const globalIndex = parseInt($btn.attr('data-idx'));

            $btn.off('click').on('click', (e) => {
                if ($(e.target).closest('.sb-edit-icon, textarea, button').length) return;
                App.insertText(content);
            });

            $btn.find('.sb-edit-icon').off('click').on('click', (e) => {
                e.stopPropagation();
                App.enterEditMode($btn, content, mesId, globalIndex);
            });
        });
    },

    enterEditMode: ($btn, content, mesId, globalIndex) => {
        const $wrapper = $(`<div class="sb-editing-wrapper"></div>`);
        const $textarea = $(`<textarea class="sb-seamless-textarea"></textarea>`).val(content);
        const $actions = $(`
            <div class="sb-action-row">
                <button class="sb-mini-btn sb-btn-cancel">取消</button>
                <button class="sb-mini-btn sb-btn-save">保存</button>
            </div>
        `);

        $wrapper.append($textarea).append($actions);
        $btn.hide().after($wrapper); 
        $textarea.height($textarea[0].scrollHeight);
        $textarea.focus();

        const closeEdit = () => { $wrapper.remove(); $btn.show(); };

        $actions.find('.sb-btn-cancel').on('click', (ev) => { ev.stopPropagation(); closeEdit(); });
        $actions.find('.sb-btn-save').on('click', (ev) => {
            ev.stopPropagation();
            const newVal = $textarea.val();
            if (newVal !== content) {
                App.syncToChatMemory(mesId, globalIndex, newVal);
                $btn.attr('data-content', newVal);
                const newHtml = App.generateBtnHtml(newVal, globalIndex);
                const $newBtn = $(newHtml);

                const $origWrapper = $btn.closest('.mes_text').find('.sb-original-wrapper');
                if ($origWrapper.length) {
                    const $targetPre = $origWrapper.find('pre').eq(globalIndex);
                    if ($targetPre.find('code').length > 0) $targetPre.find('code').text(newVal);
                    else $targetPre.text(newVal);
                }

                $btn.replaceWith($newBtn);
                $wrapper.remove(); 
                App.bindEvents($newBtn.parent(), mesId); 
                if(window.toastr) toastr.success("已更新");
            } else { closeEdit(); }
        });
    },

    scan: () => { $('#chat .mes').not('.is_user').each(function() { App.processMessage(this); }); },

    forceRefreshMessage: (mesId) => {
        const $el = $(`[mesid="${mesId}"]`);
        if ($el.length) {
            $el.removeAttr(PROCESSED_ATTR);
            setTimeout(App.scan, 50);
        }
    },

