                            ${sInput('引用块背景透明度', 'quoteBgOpacity', 100, 1, '%')}
                            ${cInput('引用块内文字色', 'quoteText', null)}
                        </div>
                    `
                },
                {
                    title: '代码与高亮',
                    preview: `<details class="sb-container sb-style-normal" open><summary class="sb-header"><span class="sb-title">重点标注</span><span class="sb-meta"></span></summary><div class="sb-content"><div class="sb-body-text">一段普通的文本中夹杂着 <code>23:50</code> 这样带有底色高亮的重要信息。</div></div></details>`,
                    settings: `
                        <div class="sb-ctrl-grid">
                            ${cInput('高亮代码文字色', 'codeText', null)}
                            ${cInput('高亮代码背景色', 'codeBg', null)}
                            ${sInput('代码背景透明度', 'codeBgOpacity', 100, 1, '%')}
                        </div>
                    `
                },
                {
                    title: '胶囊标签',
                    preview: `<details class="sb-container sb-style-normal" open><summary class="sb-header"><span class="sb-title">标签美化</span><span class="sb-meta"></span></summary><div class="sb-content"><div class="sb-body-text"><span class="sb-bracket-tag">【重要线索】</span><br>面板会自动将类似 【】 内的文本提取为独立的胶囊标签。</div></div></details>`,
                    settings: `
                        <div class="sb-ctrl-grid">
                            ${cInput('标签文字颜色', 'tagText', null)}
                            ${cInput('标签背景色', 'tagBg', null)}
                            ${sInput('标签背景透明度', 'tagBgOpacity', 100, 1, '%')}
                        </div>
                    `
                },
                {
                    title: 'RPG 标题徽章',
                    preview: `<details class="sb-container sb-style-normal" open><summary class="sb-header"><span class="sb-title">数据监控</span><span class="sb-meta"></span></summary><div class="sb-content"><div class="sb-body-text"><div class="sb-rpg-title"><span style="opacity:0.7; margin-right:4px;">❖</span>情意值记录</div><br>作为一种显眼的子标题，通常用于独立段落的开头视觉分隔。</div></div></details>`,
                    settings: `
                        <div class="sb-ctrl-grid">
                            ${cInput('RPG 徽章背景色', 'rpgBadgeBg', null)}
                            ${cInput('RPG 徽章文字色', 'rpgBadgeText', null)}
                        </div>
                    `
                },
                {
                    title: 'RPG 进度监控',
                    preview: `<details class="sb-container sb-style-normal" open><summary class="sb-header"><span class="sb-title">数据变化</span><span class="sb-meta"></span></summary><div class="sb-content"><div class="sb-body-text"><div class="sb-rpg-progress-box" style="margin: 0;"><div class="sb-rpg-progress-label"><span>温存进度</span> <span style="color:var(--sb-rpg-progress-fill);"><strong>85%</strong></span></div><div class="sb-rpg-progress-track"><div class="sb-rpg-progress-fill" style="width: 85%;"></div></div></div></div></div></details>`,
                    settings: `
                        <div class="sb-ctrl-grid">
                            ${cInput('进度条填充颜色', 'rpgProgressFill', null)}
                            ${cInput('进度条底座颜色', 'rpgProgressBg', null)}
                            ${sInput('底座颜色透明度', 'rpgProgressBgOpacity', 100, 1, '%')}
                        </div>
                    `
                }
            ];

            let slidesHtml = slides.map((slide, index) => `
                <div class="sb-carousel-slide" data-index="${index}">
                    <div class="sb-preview-wrap">
                        <span class="sb-preview-badge">预览: ${slide.title}</span>
                        ${slide.preview}
                    </div>
                    <div class="sb-scroll-area">
                        ${slide.settings}
                    </div>
                </div>
            `).join('');

            let dotsHtml = slides.map((_, index) => `<div class="sb-dot ${index === 0 ? 'active' : ''}" data-index="${index}"></div>`).join('');

            return `
                <div class="sb-theme-toolbar">
                    <div class="sb-theme-select-wrapper">
                        <select id="js-theme-select" class="sb-theme-select">
                            ${tempThemes.themes.map(t => `<option value="${t.id}" ${t.id === tempThemes.activeId ? 'selected' : ''}>${_.escape(t.name)}</option>`).join('')}
                        </select>
                    </div>
                    ${!isReadonly ? `<button class="sb-square-btn del" id="js-del-theme" title="删除">${SVGS.delete}</button>` : ''}
                    <button class="sb-square-btn" id="js-add-theme" title="新建">+</button>
                    <button class="sb-square-btn" id="js-import-theme" title="导入">${SVGS.upload}</button>
                    <button class="sb-square-btn" id="js-export-theme" title="导出">${SVGS.download}</button>
                </div>

                <div class="sb-carousel-container">
                    <div class="sb-preview-carousel" id="js-preview-carousel">
                        ${slidesHtml}
                    </div>
                    <div class="sb-carousel-dots">
                        ${dotsHtml}
                    </div>
                </div>
            `;
        };

const html = `
            <div class="sb-settings-box">
                <style id="sb-preview-sandbox"></style>
                <div class="sb-settings-header">
                    <b style="font-size:1.1em; letter-spacing:1px;">🌺美化面板🌺</b>
                    <span id="js-help-btn" class="sb-btn-icon" title="查看使用说明">${SVGS.help}</span>
                </div>
                <div class="sb-tabs">
                    <div class="sb-tab-btn active" data-target="js-tab-rules">解析规则</div>
                    <div class="sb-tab-btn" data-target="js-tab-themes">界面美化</div>
                </div>

                <div id="js-tab-rules" class="sb-tab-content active">
                    <div class="sb-help-box" style="display:none;">
                        <p style="margin:0 0 6px 0;"><b>💡 解析规则怎么用？</b></p>
                        <p style="margin:0 0 4px 0;">1. <b>标记组名称</b>：给自己看的备注，比如"剧情模拟"。</p>
                        <p style="margin:0 0 4px 0;">2. <b>外观主题</b>：选择该类卡片触发时，要使用那个美化主题。</p>
                        <p style="margin:0;">3. <b>开始/结束标记</b>：填入你提示词中让 AI 输出的特定符号，如 <code>&lt;details&gt;</code>，抓取这段符号内的内容。</p>
                        <p style="margin:0; margin-top:4px;">4. <b>互动按钮</b>：被代码块包裹的内容会变成互动按钮，点击可自动填入输入框，点击右侧 ✏️ 可直接修改聊天记录。</p>
                    </div>
                    <div class="sb-scroll-area" id="js-rules-container">${renderRulesList()}</div>
                    <button class="sb-add-btn" id="js-add-rule">${SVGS.add} 添加新标记组</button>
                </div>

                <div id="js-tab-themes" class="sb-tab-content">
                    <div class="sb-help-box" style="display:none;">
                        <p style="margin:0 0 6px 0;"><b>🎨 界面美化怎么玩？</b></p>
                        <p style="margin:0 0 4px 0;">1. <b>独立主题</b>：点击 "+" 新建不同主题，每个主题的颜色互不干扰。</p>
                        <p style="margin:0 0 4px 0;">2. <b>实时预览</b>：修改下方的颜色和数值，上方的预览图会实时变化。</p>
                        <p style="margin:0;">3. <b>导入导出</b>：遇到喜欢的分享，直接点击 📥 导入 JSON 文件即可一键换装。</p>
                    </div>
                    ${renderThemeTab()}
                </div>

                <div id="sb-hidden-inputs">
                    <input type="file" id="sb-theme-file-input" accept=".json">
                    <input type="file" id="sb-bg-upload" accept="image/*">
                </div>

                <div id="js-fs-editor" class="sb-fullscreen-overlay" style="display:none;">
                    <div class="sb-fs-header">
                        <span id="js-fs-title">全屏编辑标记</span>
                    </div>
                    <textarea id="js-fs-textarea" class="sb-fs-textarea" placeholder="在此处编辑复杂的标记代码..."></textarea>
                    <div class="sb-action-row fs-actions">
                        <button class="sb-mini-btn sb-btn-cancel" id="js-fs-cancel">取消</button>
                        <button class="sb-mini-btn sb-btn-save" id="js-fs-save">确认修改</button>
                    </div>
                </div>
            </div>
        `;

        const popupFunc = window.SillyTavern?.callGenericPopup || window.callGenericPopup;
        popupFunc(html, 1, '', { okButton: '保存并应用', cancelButton: '放弃修改' }).then(res => {
            if (res) {
                Config.save(tempConfig); ThemeConfig.save(tempThemes); ThemeConfig.apply(); 
                $(`[data-sb-milestone-processed]`).removeAttr('data-sb-milestone-processed'); setTimeout(App.scan, 500);
            }
        });

        setTimeout(() => {
            $('.sb-tab-btn').on('click', function() {
                $('.sb-tab-btn').removeClass('active'); $(this).addClass('active');
                $('.sb-tab-content').removeClass('active'); $('#' + $(this).data('target')).addClass('active');
                if ($(this).data('target') === 'js-tab-themes') { setTimeout(() => { updateActiveControlPanel(); }, 50); }
            });

            const updateSandbox = () => {
                const active = tempThemes.themes.find(t => t.id === tempThemes.activeId);
                if(active) {
                    $('.sb-carousel-slide .sb-container').each(function() {
                        this.className = this.className.replace(/\bsb-theme-[^\s]+\b/g, '');
                        $(this).addClass(`sb-theme-${active.id}`);
                    });
                    const generated = ThemeConfig.generateCssString(active.vars, active.customCss, `.sb-theme-${active.id}`);
                    $('#sb-preview-sandbox').html((generated.fontImport ? generated.fontImport + '\n' : '') + generated.cssBody);
                }
            };

            const updateActiveControlPanel = () => {
                const carousel = document.getElementById('js-preview-carousel');
                if(!carousel) return;
                const observer = new IntersectionObserver((entries) => {
                    entries.forEach(entry => {
                        if (entry.isIntersecting && entry.intersectionRatio > 0.5) {
                            const index = entry.target.getAttribute('data-index');
                            $('.sb-dot').removeClass('active');
                            $(`.sb-dot[data-index="${index}"]`).addClass('active');
                        }
                    });
                }, { root: carousel, threshold: 0.6 });

                $('.sb-carousel-slide').each(function() { observer.observe(this); });

                $('.sb-dot').off('click').on('click', function() {
                    const index = $(this).data('index');
                    const slide = document.querySelector(`.sb-carousel-slide[data-index="${index}"]`);
                    if (slide) { slide.parentNode.scrollTo({ left: slide.offsetLeft, behavior: 'smooth' }); }
                });
            };

            const bindThemeEvents = () => {
                updateSandbox();
                updateActiveControlPanel(); 

                $('#js-theme-select').on('change', function() { tempThemes.activeId = $(this).val(); $('#js-tab-themes').html(renderThemeTab()); bindThemeEvents(); });
                $('#js-add-theme').on('click', () => {
                    const newId = 'theme_' + Date.now();
                    tempThemes.themes.push({ id: newId, name: "我的自定义外观", readonly: false, vars: { ...DEFAULT_VARS }, customCss: '' });
                    tempThemes.activeId = newId; $('#js-tab-themes').html(renderThemeTab()); bindThemeEvents();
                });
                $('#js-del-theme').on('click', () => {
                    if(confirm('确定删除该美化配置吗？')) {
                        tempThemes.themes = tempThemes.themes.filter(t => t.id !== tempThemes.activeId);
                        tempThemes.activeId = tempThemes.themes[0].id; $('#js-tab-themes').html(renderThemeTab()); bindThemeEvents();
                    }
                });
                $('#js-theme-name').on('input', function() { const active = tempThemes.themes.find(t => t.id === tempThemes.activeId); if(active && !active.readonly) { active.name = $(this).val(); $('#js-theme-select option:selected').text($(this).val()); }});

                $('.sb-color-picker').on('input', function() {
                    const key = $(this).data('sync');
                    const val = $(this).val();
                    $(`input.sb-color-text[data-var="${key}"]`).val(val).trigger('input');
                });

                $('[data-var]').on('input', function() {
                    const active = tempThemes.themes.find(t => t.id === tempThemes.activeId);
                    if(active && !active.readonly) {
                        const key = $(this).data('var'); const val = $(this).val(); active.vars[key] = val;
                        if($(this).hasClass('sb-range-input')) {
                            const unit = $(this).data('unit') || '';
                            $(`#val-${key}`).text(val + unit);
                        }

                        if ($(this).hasClass('sb-color-text') && val.match(/^#[0-9A-Fa-f]{6}$/)) {
                            $(`input.sb-color-picker[data-sync="${key}"]`).val(val);
                        }
                        updateSandbox();
                    }
                });

                $('.sb-font-select').on('change', function() {
                    const active = tempThemes.themes.find(t => t.id === tempThemes.activeId);
                    if(active && !active.readonly) {
                        if($(this).data('var') === 'fontFamily') {
                            if($(this).val() === 'custom') {
                                const url = prompt("请输入字体CSS外部链接 (如Google Fonts链接):\n如果不使用外部CSS可留空", active.vars.fontUrl || "");
                                const family = prompt("请输入字体名称 (font-family):", "MyCustomFont");
                                if(family) { active.vars.fontUrl = url || ""; active.vars.fontFamily = family; }
                                $('#js-tab-themes').html(renderThemeTab()); bindThemeEvents(); 
                            } else {
                                active.vars.fontFamily = $(this).val(); active.vars.fontUrl = ""; updateSandbox();
                            }
                        }
                    }
                });

                $('#js-clear-font').on('click', function() {
                    const active = tempThemes.themes.find(t => t.id === tempThemes.activeId);
                    if(active && !active.readonly) {
                        active.vars.fontFamily = 'inherit'; active.vars.fontUrl = '';
                        $('#js-tab-themes').html(renderThemeTab()); bindThemeEvents();
                    }
                });

                $('[data-img]').on('click', function() {
                    if($(this).prop('disabled')) return;
                    window._sbCurrentImgTarget = $(this).data('img'); $('#sb-bg-upload').click();
                });

                $('[data-clear]').on('click', function() {
                    if($(this).prop('disabled')) return;
                    const target = $(this).data('clear'); const active = tempThemes.themes.find(t => t.id === tempThemes.activeId);
                    if(active) { active.vars[target] = ''; $('#js-tab-themes').html(renderThemeTab()); bindThemeEvents(); }
                });

                $('#sb-bg-upload').off('change').on('change', function(e) {
                    const file = e.target.files[0]; if(!file || !window._sbCurrentImgTarget) return;
                    const reader = new FileReader();
                    reader.onload = (ev) => {
                        const img = new Image();
                        img.onload = () => {
                            const canvas = document.createElement('canvas'); let w = img.width; let h = img.height;
                            const max = 800; 
                            if(w > max || h > max) { if(w > h) { h *= max/w; w = max; } else { w *= max/h; h = max; } }
                            canvas.width = w; canvas.height = h;
                            const ctx = canvas.getContext('2d'); ctx.drawImage(img, 0, 0, w, h);
                            const base64 = canvas.toDataURL('image/jpeg', 0.8);
                            const active = tempThemes.themes.find(t => t.id === tempThemes.activeId);
                            if(active) { active.vars[window._sbCurrentImgTarget] = base64; $('#js-tab-themes').html(renderThemeTab()); bindThemeEvents(); }
                        };
                        img.src = ev.target.result;
                    };
                    reader.readAsDataURL(file); $(this).val(''); 
                });

                $('#js-adv-toggle').on('click', () => $('#js-adv-content').slideToggle(200));
                $('#js-theme-css').on('input', function() { const active = tempThemes.themes.find(t => t.id === tempThemes.activeId); if(active && !active.readonly) { active.customCss = $(this).val(); updateSandbox(); }});

                $('#js-export-theme').on('click', () => {
                    const active = tempThemes.themes.find(t => t.id === tempThemes.activeId);
                    const blob = new Blob([JSON.stringify(active, null, 2)], {type: "application/json"});
                    const url = URL.createObjectURL(blob); const a = document.createElement('a'); a.href = url; a.download = `story_branch_theme_${active.name}.json`;
                    a.click(); URL.revokeObjectURL(url);
                });
                $('#js-import-theme').on('click', () => $('#sb-theme-file-input').click());
                $('#sb-theme-file-input').off('change').on('change', function(e) {
                    const file = e.target.files[0]; if(!file) return; const reader = new FileReader();
                    reader.onload = (ev) => {
                        try {
                            const imported = JSON.parse(ev.target.result);
                            if(imported && imported.vars) { imported.id = 'theme_' + Date.now(); imported.readonly = false; tempThemes.themes.push(imported); tempThemes.activeId = imported.id; $('#js-tab-themes').html(renderThemeTab()); bindThemeEvents(); if(window.toastr) toastr.success("导入成功！"); } else alert("无效的主题文件格式");
                        } catch(err) { alert("读取失败"); }
                    };
                    reader.readAsText(file);
                });
            };
            bindThemeEvents();

            const bindPanelEvents = () => {
                $('#js-help-btn').off('click').on('click', () => $('.sb-tab-content.active .sb-help-box').slideToggle(200));
                $('#js-add-rule').off('click').on('click', () => { tempConfig.push({ id: Date.now(), name: "新标记组", enabled: true, startMarker: "", endMarker: "", themeId: tempThemes.themes[0].id, mode: "simple", _expanded: true }); $('#js-rules-container').html(renderRulesList()); bindPanelEvents(); const container = document.getElementById('js-rules-container'); container.scrollTop = container.scrollHeight; });
                let activeInputForFs = null;
                $('#js-fs-cancel').off('click').on('click', () => { $('#js-fs-editor').fadeOut(150); });
                $('#js-fs-save').off('click').on('click', () => { if (activeInputForFs) { activeInputForFs.val($('#js-fs-textarea').val()).trigger('input'); } $('#js-fs-editor').fadeOut(150); });

                $('.sb-rule-card').each(function() {
                    const $card = $(this); const idx = $card.data('index');
                    $card.find('.sb-rule-toggle').on('change', function() { tempConfig[idx].enabled = $(this).is(':checked'); });
                    $card.find('.sb-icon-edit').on('click', function() { tempConfig[idx]._expanded = !tempConfig[idx]._expanded; $card.find('.sb-rule-body').slideToggle(200); });
                    $card.find('.sb-icon-delete').on('click', function() { if(confirm(`确定删除[${tempConfig[idx].name || '未命名'}] 吗？`)) { tempConfig.splice(idx, 1); $('#js-rules-container').html(renderRulesList()); bindPanelEvents(); }});
                    $card.find('.js-r-name').on('input', function() { tempConfig[idx].name = $(this).val(); $card.find('.sb-rule-title').text($(this).val() || "未命名标记"); });
                    $card.find('.js-r-start').on('input', function() { tempConfig[idx].startMarker = $(this).val(); });
                    $card.find('.js-r-end').on('input', function() { tempConfig[idx].endMarker = $(this).val(); });
                    $card.find('.js-r-theme').on('change', function() { tempConfig[idx].themeId = $(this).val(); });
                    $card.find('.js-r-mode').on('change', function() { tempConfig[idx].mode = $(this).val(); });
                    $card.find('.sb-expand-btn').on('click', function() { const isStart = $(this).data('target') === 'start'; activeInputForFs = $card.find(isStart ? '.js-r-start' : '.js-r-end'); $('#js-fs-title').text(isStart ? '全屏编辑：开始标记' : '全屏编辑：结束标记'); $('#js-fs-textarea').val(activeInputForFs.val()); $('#js-fs-editor').fadeIn(150, () => { $('#js-fs-textarea').focus(); }); });
                });
            };
            bindPanelEvents();
        }, 100);
    },

    init: () => {
        ThemeConfig.apply(); 
        if (window.SillyTavern?.SlashCommandParser) {
            SillyTavern.SlashCommandParser.addCommandObject(SillyTavern.SlashCommand.fromProps({ name: 'sb-panel', callback: App.openSettings, helpString: '🌺美化面板🌺' }));
        }
        if (typeof appendInexistentScriptButtons === 'function') { 
            appendInexistentScriptButtons([{ name: "🌺美化面板🌺", visible: true }]); 
            if (window.eventOn) window.eventOn(getButtonEvent("🌺美化面板🌺"), App.openSettings); 
        }
        if (window.eventOn && window.tavern_events) { 
            const triggerRefresh = (id) => { if (typeof id === 'number') App.forceRefreshMessage(id); else setTimeout(() => { $(`[${PROCESSED_ATTR}]`).removeAttr(PROCESSED_ATTR); App.scan(); }, 100); };[tavern_events.MESSAGE_RECEIVED, tavern_events.MESSAGE_UPDATED, tavern_events.MESSAGE_EDITED, tavern_events.MESSAGE_SWIPED, tavern_events.GENERATION_ENDED, tavern_events.CHARACTER_MESSAGE_RENDERED, tavern_events.USER_MESSAGE_RENDERED].forEach(evt => window.eventOn(evt, triggerRefresh)); 
            window.eventOn(tavern_events.CHAT_CHANGED, () => setTimeout(App.scan, 500)); 
        }
        $('[class*="sb-group-v"]').remove(); $('[data-sb-v41-processed],[data-sb-v42-processed],[data-sb-v43-processed],[data-sb-v44-processed]').removeAttr('data-sb-v41-processed').removeAttr('data-sb-v42-processed').removeAttr('data-sb-v43-processed').removeAttr('data-sb-v44-processed');
        App.scan(); console.log(LOG_PREFIX, "Visual Theme Sandbox UI Loaded.");
    }
};

setTimeout(App.init, 1000);

// ==UserScript==
