    const FormBuilder = {
        render: (schemaKey) => {
            const schema = FormSchemas[schemaKey];
            if (!schema) return '<div>配置错误</div>';
            let html = `<div class="divine-form-container" data-schema="${schemaKey}">`;
            schema.fields.forEach(field => html += FormBuilder.renderField(field));
            html += `</div>`;
            return html;
        },

        renderField: (field) => {
            let html = `
                <div class="divine-form-group" 
                     data-field-id="${field.id}" 
                     data-type="${field.type}" 
                     data-label="${field.label}"
                     data-desc="${field.desc}"
                     data-format="${field.outputFormat || ''}">
                    <label class="divine-form-label">${field.label}</label>
                    <span class="divine-form-desc">${field.desc.replace(/\n/g, '<br>')}</span>
            `;
            if (field.example) {
                html += `<span class="divine-form-example">${field.example}</span>`;
            }

            if (field.type === 'text') {
                html += `<input type="text" class="divine-form-input" placeholder="输入参数...">`;
            } else if (field.type === 'textarea') {
                html += `<textarea class="divine-form-textarea" placeholder="输入详细描述..."></textarea>`;
            } else if (field.type === 'array') {
                html += `
                    <div class="divine-array-container" data-item-label="${field.itemLabel}"></div>
                    <div class="divine-btn-add" data-schema='${JSON.stringify(field.subFields)}'>+ 新增 ${field.itemLabel}</div>
                `;
            }
            html += `</div>`;
            return html;
        },

        bindEvents: ($container) => {
            $container.find('.divine-btn-add').on('click', function() {
                const subFields = $(this).data('schema');
                const $wrapper = $(this).prev('.divine-array-container');
                const itemLabel = $wrapper.data('item-label');

                let itemHtml = `<div class="divine-array-item">
                    <div class="divine-array-item-title">
                        ♡ ${itemLabel}
                        <span class="divine-btn-remove">✖</span>
                    </div>
                `;
                subFields.forEach(sf => {
                    itemHtml += `
                        <div class="divine-sub-field">
                            <div class="divine-sub-label">${sf.label}</div>
                            <input type="text" class="divine-form-input" style="padding:6px; font-size:0.9em;" 
                                   data-sub-id="${sf.id}" placeholder="${sf.placeholder || ''}">
                        </div>
                    `;
                });
                itemHtml += `</div>`;

                const $node = $(itemHtml);
                $wrapper.append($node);
                $node.find('.divine-btn-remove').on('click', function() { $(this).closest('.divine-array-item').remove(); });
            });
        },

        generateData: ($container, schemaKey) => {
            const schema = FormSchemas[schemaKey];
            let requestText = schema.templateHeader;
            let outputTemplateParts = [];
            let hasContent = false;

            $container.find('.divine-form-group').each(function() {
                const label = $(this).data('label');
                const desc = $(this).data('desc');
                const type = $(this).data('type');
                const format = $(this).data('format');
                let blockContent = '';

                if (type === 'text') blockContent = $(this).find('input').val().trim();
                else if (type === 'textarea') blockContent = $(this).find('textarea').val().trim();
                else if (type === 'array') {
                    const $items = $(this).find('.divine-array-item');
                    if ($items.length > 0) {
                        const itemLabel = $(this).find('.divine-array-container').data('item-label');
                        $items.each(function(i) {
                            let itemStr = `\n  [${itemLabel} 0${i + 1}] > `;
                            let subParts = [];
                            $(this).find('input').each(function() {
                                const val = $(this).val().trim();
                                const subLabel = $(this).prev().text();
                                if (val) subParts.push(`<${subLabel}: ${val}>`);
                            });
                            if (subParts.length > 0) itemStr += subParts.join(' | ');
                            blockContent += itemStr;
                        });
                    }
                }

                if (blockContent) {
                    hasContent = true;
                    requestText += `\n【维度：${label}】\n描述：${desc}\n具体设定：${blockContent}\n`;
                    if (format) outputTemplateParts.push(format);
                }
            });

            if (hasContent) {
                requestText += schema.templateOutputHead;
                requestText += outputTemplateParts.join('\n');
                requestText += schema.templateOutputTail;
                return requestText;
            }
            return null;
        }
    };

