        showPage: (key, $content, popup) => {
            const page = Logic.pages[key];
            if (!page) return;

            const $wrap = $content.closest('.divine-wrapper');
            let title = page.title;
            let sub = page.subtitle;
            if (page.isForm) {
                const s = FormSchemas[page.schemaKey];
                title = '🌸 ' + s.title;
                sub = s.subtitle;
            }
            $wrap.find('.divine-title').text(title);
            $wrap.find('.divine-subtitle').text(sub);

            $content.empty();
            if (page.isForm) {
                $content.html(FormBuilder.render(page.schemaKey));
                FormBuilder.bindEvents($content);
            } else {
                $content.html(page.content);
            }

            const $ft = $wrap.find('.divine-footer').length ? $wrap.find('.divine-footer') : $('<div class="divine-footer"></div>').appendTo($wrap);
            $ft.empty();

            if (page.parent) {
                $('<button class="compact-btn">← 返回</button>').on('click', () => Logic.showPage(page.parent, $content, popup)).appendTo($ft);
            }

            if (page.isForm) {
                $('<button class="compact-btn primary">💌 注入参数</button>').on('click', () => {
                    const data = FormBuilder.generateData($content, page.schemaKey);
                    if (!data) return alert('提示：内容不可为空');
                    if (confirm(`【指令预览】\n\n${data.substring(0,500)}...\n\n(确认无误并注入？)`)) {
                        Logic.injectContent(data);
                        if (popup?.completeAffirmative) popup.completeAffirmative();
                        else $('.swal2-confirm').click();
                    }
                }).appendTo($ft);
            }

            $('<button class="compact-btn close">关闭终端</button>').on('click', () => {
                if (popup?.completeAffirmative) popup.completeAffirmative();
                else $('.swal2-confirm').click();
            }).appendTo($ft);

            if (!page.isForm) {
                $content.find('[data-module]').on('click', function() { Logic.showPage($(this).data('module'), $content, popup); });
                $content.find('[data-form]').on('click', function() { Logic.showPage($(this).data('form'), $content, popup); });
                $content.find('[data-key]').on('click', function() { 
                    if(Logic.injectContent(ContentLibrary[$(this).data('key')])) $('.compact-btn.close').click(); 
                });
                $content.find('[data-action]').on('click', function() {
                    const act = $(this).data('action');
                    if (act === 'hide' || act === 'unhide') {
                        const r = prompt(act==='hide'?'请输入范围(如0-10)':'确认取消隐藏');
                        if(r && Logic.injectContent(`/${act} ${r}`)) $('.compact-btn.close').click();
                    } else if (act === 'scene-switch') {
                        const scene = prompt('请输入目标场景（地点 + 时间），例如：景山别墅 傍晚六点');
                        if (scene) {
                            const cmd = ContentLibrary['flow-scene'].replace('[USER_INPUT]', scene) + `\n目标场景：${scene}`;
                            if(Logic.injectContent(cmd)) $('.compact-btn.close').click();
                        }
                    } else if (act === 'custom-jud') {
                        const custom = prompt('请输入你的修正要求：');
                        if (custom) {
                            const cmd = ContentLibrary['jud-custom'].replace('[USER_INPUT]', custom);
                            if(Logic.injectContent(cmd)) $('.compact-btn.close').click();
                        }
                    }
                });
            }
        }
    };

