    const initUI = () => {
        try {
            const $wrap = $('<div class="divine-wrapper"></div>');
            $wrap.append('<div class="divine-header-group"><h1 class="divine-title"></h1><div class="divine-subtitle"></div></div><div class="divine-scroll-content"></div><div class="divine-footer"></div>');

            let popup = null;
            if (window.SillyTavern?.Popup) {
                popup = new SillyTavern.Popup($wrap, SillyTavern.POPUP_TYPE.TEXT, "", { okButton:false, wide:true, large:true });
                popup.show();
            } else {
                (window.SillyTavern?.callGenericPopup || window.callGenericPopup)($wrap, 1, "", {okButton:false});
            }
            Logic.showPage('main', $wrap.find('.divine-scroll-content'), popup);
        } catch(e) { console.error(e); alert('Error: '+e.message); }
    };

    const register = () => {
        if (typeof appendInexistentScriptButtons === 'function') {
            appendInexistentScriptButtons([{ name: BTN_NAME, visible: true }]);
            eventOn(getButtonEvent(BTN_NAME), initUI);
        } else {
            const $qr = $('#quick-reply-container, .quickReplyContainer');
            if ($qr.length && !$('#narrative-core-btn').length) {
                $qr.prepend(`<div id="narrative-core-btn" style="cursor:pointer;display:inline-block;padding:6px 12px;border:1px solid #ffc2d4;margin:2px;color:#e56b8f;background:rgba(255,255,255,0.8);border-radius:8px;font-size:12px;letter-spacing:1px;font-weight:bold;">${BTN_NAME}</div>`);
                $('#narrative-core-btn').on('click', initUI);
            }
        }
    };
    setTimeout(register, 1200);
